293→void ALFPTacticsUnit::FinishMove()
294→{
295→    // 更新到目标位置
296→    if (TargetTile)
297→    {
298→        SetCurrentCoordinates(TargetTile->GetCoordinates());
299→        // 计算路径实际移动代价（考虑地形）
300→        int32 TotalCost = 0;
301→        for (ALFPHexTile* Tile : MovePath)
302→        {
303→            TotalCost += Tile->GetMovementCost();
304→        }
305→        ConsumeMovePoints(TotalCost);
306→        //SetActorLocation(TargetTile->GetActorLocation() + FVector(0, 0, 50));
307→    }
308→
309→    // 清除移动状态
310→    TargetTile = nullptr;
311→    MovePath.Empty();
312→    CurrentPathIndex = -1;
313→    MoveProgress = 0.0f;
314→}
